  // Root.sc.html is parsed as JSX so the whitespace between slide elements
  // becomes string children. Filter those out — otherwise slides.length is
  // ~2x the real count and the n/total counter goes haywire.
  const slides = React.Children.toArray(children).filter(
    (c) => typeof c !== 'string' || c.trim() !== '',
  );
  const [idx, setIdx] = React.useState(0);
  const userTookControl = React.useRef(false);
  const prevCount = React.useRef(slides.length);

  // Fit the 1280x720 stage to the viewport with letterboxing. ResizeObserver
  // on the outer fixed container so we react to window resizes and any
  // parent layout changes. Allow scaling above 1 — slides should fill.
  const outerRef = React.useRef(null);
  const [scale, setScale] = React.useState(1);
  React.useEffect(() => {
    const el = outerRef.current;
    if (!el) return;
    const update = () => {
      const w = el.clientWidth;
      const h = el.clientHeight;
      if (!w || !h) return;
      setScale(Math.min(w / 1280, h / 720));
    };
    update();
    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

