  // looking at slide 1. Auto-advance to the tail until the user grabs
  // control, so they see the new content as it arrives.
  React.useEffect(() => {
    if (slides.length > prevCount.current && !userTookControl.current) {
      setIdx(slides.length - 1);
    }
    prevCount.current = slides.length;
  }, [slides.length]);

  const total = slides.length || 1;
  const safeIdx = Math.max(0, Math.min(idx, total - 1));

  const go = React.useCallback(
    (next) => {
      userTookControl.current = true;
      setIdx(Math.max(0, Math.min(total - 1, next)));
    },
    [total],
  );

